const now = new Date();
const rows = $input.all().flatMap((item) => Array.isArray(item.json) ? item.json : [item.json]);
const stale = rows
  .filter((row) => row && typeof row === 'object' && row.id)
  .map((row) => {
    const baseline = row.updated_at || row.created_at;
    const ageDays = baseline ? Math.floor((now.getTime() - new Date(baseline).getTime()) / 86400000) : 0;
    return { ...row, ageDays };
  })
  .filter((row) => row.ageDays >= 3)
  .sort((a, b) => b.ageDays - a.ageDays);
const count = stale.length;
const subject = count > 0
  ? `Proposal follow-up watchlist: ${count}`
  : 'Proposal follow-up watchlist: clear';
const listItems = stale.slice(0, 25).map((row) => {
  const value = row.estimated_value ?? 0;
  const expectedClose = row.expected_close_date || 'n/a';
  return `<li>Opportunity #${row.id} - ${row.name} - ${row.ageDays} day(s) stale - estimated value $${value} - expected close ${expectedClose}</li>`;
});
const html = count > 0
  ? `<p>${count} proposal-stage opportunity/opportunities have not moved in at least three days.</p><ul>${listItems.join('')}</ul><p>Use this list to schedule follow-up and log the next activity in CRM.</p>`
  : '<p>No proposal-stage opportunities are older than three days without movement.</p>';
const text = count > 0
  ? `${count} proposal-stage opportunities need follow-up. Review the CRM opportunity queue.`
  : 'No proposal-stage opportunities need follow-up.';
return [{ json: { count, subject, html, text } }];
